import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you calculate ovulation date?", a: "Ovulation is commonly estimated about 14 days before the next period, based on average cycle length." },
  { q: "What is the fertile window?", a: "The fertile window is usually the five days before ovulation through about one day after ovulation." },
  { q: "How long does ovulation last?", a: "The egg can usually be fertilized for about 12 to 24 hours after ovulation." },
  { q: "What are signs of ovulation?", a: "Common signs can include changes in cervical mucus, mild pelvic pain, libido changes, and a rise in basal body temperature after ovulation." },
  { q: "How does cycle length affect ovulation date?", a: "Longer cycles typically mean ovulation happens later, while shorter cycles usually mean it happens earlier." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const fmt = (d: Date) => d.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" });
const add = (d: Date, days: number) => { const next = new Date(d); next.setDate(next.getDate() + days); return next; };

export default function OvulationCalculator() {
  const [lmp, setLmp] = useState("2026-05-01");
  const [cycle, setCycle] = useState(28);
  const result = useMemo(() => {
    const start = new Date(`${lmp}T00:00:00`);
    const ovulation = add(start, cycle - 14);
    return { start, ovulation, fertileStart: add(ovulation, -5), fertileEnd: add(ovulation, 1), nextPeriod: add(start, cycle) };
  }, [lmp, cycle]);
  const rows = [26, 27, 28, 29, 30, 31, 32, 35].map((c) => { const ov = add(result.start, c - 14); return [c, fmt(result.start), fmt(ov), fmt(add(ov, -5)), fmt(add(ov, 1)), fmt(add(result.start, c))]; });
  return (
    <>
      <SEOHead title="Free Ovulation Calculator Online - Calculate Your Ovulation Date and Fertile Window Instantly | CalcHive" description="Free online ovulation calculator. Calculate your ovulation date, fertile window and best days to conceive from your last period and cycle length instantly. 100% free, no signup required." canonical="/ovulation-calculator" keywords="free ovulation calculator, ovulation date calculator free online, fertile window calculator free, best days to get pregnant calculator free, ovulation predictor calculator free" category="Health Calculators" breadcrumbName="Free Ovulation Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Ovulation Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate ovulation date, fertile window, next period, and best days to conceive.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">First day of last period</label><input type="date" value={lmp} onChange={(e) => setLmp(e.target.value)} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Average cycle length</label><input type="number" value={cycle} onChange={(e) => setCycle(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated Ovulation Date</p><p className="text-4xl sm:text-5xl font-black text-white">{fmt(result.ovulation)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fertile window start</p><p className="text-lg font-extrabold">{fmt(result.fertileStart)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Fertile window end</p><p className="text-lg font-extrabold">{fmt(result.fertileEnd)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Next period</p><p className="text-lg font-extrabold">{fmt(result.nextPeriod)}</p></div></div></section><MedicalDisclaimer variant="pregnancy" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Ovulation Date for Free</h2><p className="text-muted-foreground leading-relaxed">Ovulation is estimated by subtracting 14 days from your next expected period date.</p><h2 className="text-2xl font-bold">How to Find Your Fertile Window for Maximum Conception Chances</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Ovulation and Fertile Window by Cycle Length</caption><thead className="bg-muted/60"><tr>{["Cycle Length", "Period Start", "Ovulation Day", "Fertile Window Start", "Fertile Window End", "Next Period"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={String(r[0])}>{r.map((c) => <td key={String(c)} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Ovulation and Fertility Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/ovulation-calculator" headingLevel="h3" /></main>
    </>
  );
}


